   311→/**
   312→ * Alphabet filter support for CCT queries (JetSmartFilters + JetEngine CCT)
   313→ *
   314→ * JetSmartFilters stores the selected letter in final_query['alphabet'],
   315→ * but CCT_Query::_get_items() ignores it. This hook converts the letter
   316→ * to a LIKE condition on item_title so the alphabet filter works with CCT.
   317→ *
   318→ * @since 1.5.1
   319→ */
   320→add_action('jet-engine/query-builder/query/before-get-items', 'bureau_it_cct_alphabet_filter', 10, 2);
   321→function bureau_it_cct_alphabet_filter($query, $cached) {
   322→    if ($cached) {
   323→        return;
   324→    }
   325→
   326→    if ($query->query_type !== 'custom-content-type') {
   327→        return;
   328→    }
   329→
   330→    if (empty($query->final_query['alphabet'])) {
   331→        return;
   332→    }
   333→
   334→    $letter = $query->final_query['alphabet'];
   335→    if (is_array($letter)) {
   336→        $letter = reset($letter);
   337→    }
   338→    $letter = mb_substr(sanitize_text_field($letter), 0, 1);
   339→
   340→    if (empty($letter)) {
   341→        return;
   342→    }
   343→
   344→    if (!isset($query->final_query['args']) || !is_array($query->final_query['args'])) {
   345→        $query->final_query['args'] = array();
   346→    }
   347→
   348→    $query->final_query['args'][] = array(
   349→        'field'    => 'item_title',
   350→        'operator' => 'LIKE',
   351→        'value'    => $letter . '%',
   352→    );
   353→
   354→    unset($query->final_query['alphabet']);
   355→}
