   496→add_action('wp_enqueue_scripts', 'bureau_it_dequeue_unused_jet_assets', 999);
   497→function bureau_it_dequeue_unused_jet_assets() {
   498→    if (is_admin() || !is_singular()) {
   499→        return;
   500→    }
   501→
   502→    $post_id = get_the_ID();
   503→    if (!$post_id) {
   504→        return;
   505→    }
   506→
   507→    $data = get_post_meta($post_id, '_elementor_data', true);
   508→    if (empty($data)) {
   509→        return;
   510→    }
   511→
   512→    // JetElements widgets that require JS (sliders, carousels, etc.)
   513→    $jet_js_widgets = [
   514→        'jet-slider',
   515→        'jet-carousel',
   516→        'jet-posts',
   517→        'jet-animated-text',
   518→        'jet-testimonials',
   519→        'jet-image-comparison',
   520→        'jet-countdown-timer',
   521→        'jet-accordion',
   522→        'jet-tabs',
   523→        'jet-toggle',
   524→    ];
   525→
   526→    $needs_jet_js = false;
   527→    foreach ($jet_js_widgets as $widget) {
   528→        if (strpos($data, '"widgetType":"' . $widget . '"') !== false) {
   529→            $needs_jet_js = true;
   530→            break;
   531→        }
   532→    }
   533→
   534→    if (!$needs_jet_js) {
   535→        wp_dequeue_script('jet-elements');
   536→        wp_deregister_script('jet-elements');
   537→    }
   538→
   539→    // Dequeue JetSmartFilters if page doesn't use filter widgets
   540→    $filter_widgets = ['jet-smart-filters-', 'jsfb-'];
   541→    $needs_filters  = false;
   542→    foreach ($filter_widgets as $widget) {
   543→        if (strpos($data, $widget) !== false) {
   544→            $needs_filters = true;
   545→            break;
   546→        }
   547→    }
   548→
   549→    if (!$needs_filters) {
   550→        wp_dequeue_script('jet-smart-filters');
   551→        wp_deregister_script('jet-smart-filters');
   552→    } else {
   553→        // Força CSS no <head> via fila normal — compatível com WP Rocket.
   554→        // O mecanismo padrão do JSF imprime CSS mid-body via wp_print_styles(),
   555→        // que o WP Rocket remove ao combinar CSS. Forçar aqui garante que o
   556→        // <link> seja emitido pelo wp_head() antes do cache ser gerado.
   557→        if (function_exists('jet_smart_filters') && wp_style_is('jet-smart-filters', 'registered')) {
   558→            wp_enqueue_style('jet-smart-filters');
   559→            jet_smart_filters()->filters_not_used = false; // evita print mid-body duplicado
   560→        }
   561→    }
   562→}
   563→
   564→/**
   565→ * ============================================================================
   566→ * PERFORMANCE: Lazy loading para imagens
   567→ * ============================================================================
   568→ *
   569→ * Adiciona loading="lazy" para imagens que nao possuem o atributo.
   570→ *
   571→ * @since 1.5.0
   572→ */
   573→add_filter('wp_get_attachment_image_attributes', 'bureau_it_optimize_image_loading', 10, 3);
   574→function bureau_it_optimize_image_loading($attr, $attachment, $size) {
   575→    // banner-home usa slick carousel com infinite clone — lazy loading quebra imagens em slides clonados
   576→    if (get_post_type() === 'banner-home') {
   577→        $attr['loading'] = 'eager';
   578→        return $attr;
   579→    }
   580→    if (!isset($attr['loading'])) {
   581→        $attr['loading'] = 'lazy';
   582→    }
   583→    return $attr;
   584→}
