   586→/**
   587→ * ============================================================================
   588→ * ELEMENTOR PRO BUG FIX: SVG Links
   589→ * ============================================================================
   590→ *
   591→ * Fix para bug do Elementor Pro 3.33.x onde o módulo Off-Canvas falha ao
   592→ * processar links dentro de elementos SVG. O erro ocorre porque links SVG
   593→ * retornam SVGAnimatedString (objeto) ao invés de string para a propriedade
   594→ * .href, e o Elementor tenta chamar .includes() que não existe nesse objeto.
   595→ *
   596→ * Este fix adiciona o método .includes() ao prototype de SVGAnimatedString.
   597→ *
   598→ * @since 1.4.1
   599→ * @see https://github.com/elementor/elementor/issues/XXXXX
   600→ */
   601→add_action('wp_head', 'bureau_it_fix_elementor_svg_links', 1);
   602→function bureau_it_fix_elementor_svg_links() {
   603→    ?>
   604→    <script>
   605→    // Fix: Elementor Pro Off-Canvas + SVG links compatibility
   606→    // SVGAnimatedString doesn't have .includes(), causing TypeError
   607→    if (typeof SVGAnimatedString !== 'undefined' && !SVGAnimatedString.prototype.includes) {
   608→        SVGAnimatedString.prototype.includes = function(searchString) {
   609→            return this.baseVal.includes(searchString);
   610→        };
   611→    }
   612→    </script>
   613→    <?php
   614→}
   615→
   616→/**
   617→ * ============================================================================
   618→ * MULTISITE: Shared uploads symlinks (subsite blog_id=2)
   619→ * ============================================================================
   620→ *
   621→ * Subsite /cultura/ generates upload URLs with /sites/2/YYYY/MM/ but actual
   622→ * files are in /wp-content/uploads/YYYY/MM/ (shared from single-site era).
   623→ * Creates symlinks sites/2/YYYY -> ../../YYYY on first request if missing.
   624→ *
   625→ * @since 1.6.1
   626→ */
   627→add_action('init', 'bureau_it_ensure_shared_upload_symlinks', 1);
   628→function bureau_it_ensure_shared_upload_symlinks() {
   629→    if (!is_multisite() || get_current_blog_id() !== 2) {
   630→        return;
   631→    }
   632→
   633→    $upload_dir = ABSPATH . 'wp-content/uploads';
   634→    $sites_dir  = "$upload_dir/sites/2";
   635→
   636→    if (!is_dir($sites_dir)) {
   637→        @mkdir($sites_dir, 0755, true);
   638→    }
   639→
   640→    foreach (glob("$upload_dir/20[0-9][0-9]", GLOB_ONLYDIR) as $year_dir) {
   641→        $year = basename($year_dir);
   642→        $link = "$sites_dir/$year";
   643→        if (!file_exists($link)) {
   644→            @symlink("../../$year", $link);
   645→        }
   646→    }
   647→}
